import React, { useEffect, useState } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import './Menu.css';

const Home = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [currentPath, setCurrentPath] = useState(location.pathname);

  const handleMenuClick = (event, targetPath) => {
    if (location.pathname.startsWith(targetPath)) {
      window.location.href = targetPath; // Полная перезагрузка страницы
      event.preventDefault();
    }
  };

  useEffect(() => {
    setCurrentPath(location.pathname);
  }, [location]);

  return (
    <div className='body'>
      <div id='menubackimage' />
      <div className="menubox">
        <div className="menulinks">
          <div className={`menulinkschapter ${currentPath === '/' ? 'now' : ''}`} id="main">
            <Link to='/' className="menulinkschaptertext" onClick={(e) => handleMenuClick(e, '/')}>
              ГЛАВНАЯ
            </Link>
          </div>
          <div className={`menulinkschapter ${currentPath.startsWith('/shop') ? 'now' : ''}`} id="shop">
            <Link to='/shop' className="menulinkschaptertext" onClick={(e) => handleMenuClick(e, '/shop')}>
              МАГАЗИН
            </Link>
          </div>
          <div className={`menulinkschapter ${currentPath.startsWith('/music') ? 'now' : ''}`} id="music">
            <Link to='/music' className="menulinkschaptertext" onClick={(e) => handleMenuClick(e, '/music')}>
              МУЗЫКА
            </Link>
          </div>
          <div className={`menulinkschapter ${currentPath.startsWith('/tickets') ? 'now' : ''}`} id="tickets">
            <Link to='/tickets' className="menulinkschaptertext" onClick={(e) => handleMenuClick(e, '/tickets')}>
              БИЛЕТЫ
            </Link>
          </div>
          <div className={`menulinkschapter ${currentPath.startsWith('/contacts') ? 'now' : ''}`} id="contacts">
            <Link to='/contacts' className="menulinkschaptertext" onClick={(e) => handleMenuClick(e, '/contacts')}>
              КОНТАКТЫ
            </Link>
          </div>
        </div>
      </div>
      <div className='menulright'>
        <Link to='/' className='menulrighttext'>
          л.
        </Link>
      </div>
    </div>
  );
};

export default Home;

// функция для отслеживания url для изменения стилей главного меню
(function(history) {
  const pushState = history.pushState;
  const replaceState = history.replaceState;

  history.pushState = function(state, title, url) {
    const result = pushState.apply(history, arguments);
    window.dispatchEvent(new Event('urlchange'));
    return result;
  };

  history.replaceState = function(state, title, url) {
    const result = replaceState.apply(history, arguments);
    window.dispatchEvent(new Event('urlchange'));
    return result;
  };

  window.addEventListener('urlchange', updatePage);
  window.addEventListener('popstate', updatePage);
  window.addEventListener('load', updatePage);

  function updatePage() {
    let loca = window.location.pathname.slice(1);
    const current = document.querySelector('.now');
    if (current) {
      current.classList.remove('now');
    }

    if (loca === '') {
      const main = document.querySelector('#main');
      if (main) {
        main.classList.add('now');
      }
    } else if (loca.startsWith('shop')) {
      const shop = document.querySelector('#shop');
      if (shop) {
        shop.classList.add('now');
      }
    } else if (loca.startsWith('music')) {
      const music = document.querySelector('#music');
      if (music) {
        music.classList.add('now');
      }
    } else if (loca.startsWith('tickets')) {
      const tickets = document.querySelector('#tickets');
      if (tickets) {
        tickets.classList.add('now');
      }
    } else if (loca.startsWith('contacts')) {
      const contacts = document.querySelector('#contacts');
      if (contacts) {
        contacts.classList.add('now');
      }
    }
  }
})(window.history);